// Build the evening check-in message
const meals = $('Fetch Today\'s Food').all().map(i => i.json);
const stepData = $('Fetch Today\'s Steps').first()?.json || {};

let totalCal = 0, totalProtein = 0, totalCarbs = 0, totalFat = 0;
for (const m of meals) {
  totalCal += m.calories || 0;
  totalProtein += parseFloat(m.protein_g) || 0;
  totalCarbs += parseFloat(m.carbs_g) || 0;
  totalFat += parseFloat(m.fat_g) || 0;
}

const today = new Date();
const dayOfWeek = today.getDay();
const isTrainingDay = [1, 3, 5].includes(dayOfWeek);
const goal = isTrainingDay ? 2100 : 1900;
const steps = stepData.steps || 0;

const foodSummary = meals.length > 0
  ? `You logged ${meals.length} meals today: ${totalCal} kcal, ${Math.round(totalProtein)}g protein`
  : 'No food logged today!';

const calStatus = totalCal > 0 && totalCal <= goal + 100 ? '✅' : '⚠️';
const proteinStatus = totalProtein >= 140 ? '✅' : '⚠️';
const stepStatus = steps >= 10000 ? '✅' : `${steps.toLocaleString()} so far`;

const message = `Hey! Time for your evening check-in.

📊 Today's numbers:
${calStatus} Calories: ${totalCal} / ${goal} kcal
${proteinStatus} Protein: ${Math.round(totalProtein)} / 170g
👟 Steps: ${stepStatus}

Which of these did you do today?
• 😴 Sleep (8 hours last night?)
• 💪 Workout
• 📖 Read/Learn 30 min
• 💊 Supplements
• 📅 Calendar & Reflection
• 🙏 Positivity/Gratefulness

Just reply with what you did. I'll log everything.`;

return [{
  json: {
    message,
    totalCal,
    totalProtein: Math.round(totalProtein * 10) / 10,
    totalCarbs: Math.round(totalCarbs * 10) / 10,
    totalFat: Math.round(totalFat * 10) / 10,
    isTrainingDay,
    goal,
    mealCount: meals.length,
    steps
  }
}];
